'''This module implements deepracer checkpoint json file specifically'''

import os
import logging
import json
import hashlib
import botocore

from markov.log_handler.logger import Logger
from markov.log_handler.exception_handler import log_and_exit
from markov.log_handler.deepracer_exceptions import GenericNonFatalException
from markov.log_handler.constants import (SIMAPP_EVENT_ERROR_CODE_500,
                                          SIMAPP_SIMULATION_WORKER_EXCEPTION)
from markov.boto.s3.s3_client import S3Client
from markov.boto.s3.constants import (DEEPRACER_CHECKPOINT_KEY_POSTFIX,
                                      DEEPRACER_CHECKPOINT_LOCAL_PATH_FORMAT,
                                      BEST_CHECKPOINT,
                                      LAST_CHECKPOINT)

LOG = Logger(__name__, logging.INFO).get_logger()


class DeepracerCheckpointJson():
    '''This class is for deepracer checkpoint json file upload and download
    '''
    def __init__(self, bucket, s3_prefix, region_name='us-east-1',
                 s3_endpoint_url=None,
                 local_dir='.checkpoint/agent',
                 max_retry_attempts=0, backoff_time_sec=1.0,
                 log_and_cont: bool = False):
        '''This class is for deepracer checkpoint json file upload and download

        Args:
            bucket (str): S3 bucket string.
            s3_prefix (str): S3 prefix string.
            region_name (str): S3 region name.
                               Defaults to 'us-east-1'.
            local_dir (str, optional): Local file directory.
                                       Defaults to '.checkpoint/agent'.
            max_retry_attempts (int, optional): Maximum number of retry attempts for S3 download/upload.
                                                Defaults to 0.
            backoff_time_sec (float, optional): Backoff second between each retry.
                                                Defaults to 1.0.
            log_and_cont (bool, optional): Log the error and continue with the flow.
                                           Defaults to False.
        '''
        if not bucket or not s3_prefix:
            log_and_exit("checkpoint S3 prefix or bucket not available for S3. \
                         bucket: {}, prefix {}"
                         .format(bucket, s3_prefix),
                         SIMAPP_SIMULATION_WORKER_EXCEPTION,
                         SIMAPP_EVENT_ERROR_CODE_500)
        self._bucket = bucket
        # deepracer checkpoint json s3 key
        self._s3_key = os.path.normpath(os.path.join(
            s3_prefix,
            DEEPRACER_CHECKPOINT_KEY_POSTFIX))
        # deepracer checkpoint json local path
        self._local_path = os.path.normpath(
            DEEPRACER_CHECKPOINT_LOCAL_PATH_FORMAT.format(local_dir))
        self._s3_client = S3Client(region_name,
                                   s3_endpoint_url,
                                   max_retry_attempts,
                                   backoff_time_sec,
                                   log_and_cont=log_and_cont)

    def _get_deepracer_checkpoint(self, checkpoint_type):
        '''Returns the deepracer checkpoint stored in the checkpoint json

        Args:
           checkpoint_type (str): BEST_CHECKPOINT/LAST_CHECKPOINT string
        '''
        try:
            # Download deepracer checkpoint
            self._download()
        except GenericNonFatalException as ex:
            raise ex
        except botocore.exceptions.ClientError as err:
            if err.response['Error']['Code'] == "404":
                LOG.info("Unable to find deepracer checkpoint json")
                return None
            else:
                log_and_exit("Unable to download deepracer checkpoint json: {}, {}".
                             format(self._bucket, err.response['Error']['Code']),
                             SIMAPP_SIMULATION_WORKER_EXCEPTION,
                             SIMAPP_EVENT_ERROR_CODE_500)
        except Exception as ex:
            log_and_exit("Can't download deepracer checkpoint json: {}".format(ex),
                         SIMAPP_SIMULATION_WORKER_EXCEPTION,
                         SIMAPP_EVENT_ERROR_CODE_500)
        try:
            with open(self._local_path) as deepracer_checkpoint_file:
                checkpoint_name = json.load(deepracer_checkpoint_file)[checkpoint_type]["name"]
                if not checkpoint_name:
                    raise Exception("No deepracer checkpoint json recorded")
            os.remove(self._local_path)
        except Exception as ex:
            LOG.info("Unable to parse deepracer checkpoint json: {}".format(ex))
            return None
        return checkpoint_name

    def get_deepracer_best_checkpoint(self):
        '''get the best deepracer checkpoint name

        Returns:
            str: best checkpoint name string
        '''
        return self._get_deepracer_checkpoint(BEST_CHECKPOINT)

    def get_deepracer_last_checkpoint(self):
        '''get the last deepracer checkpoint name

        Returns:
            str: last checkpoint name string
        '''
        return self._get_deepracer_checkpoint(LAST_CHECKPOINT)

    def get_deepracer_best_checkpoint_number(self):
        '''get the best deepracer checkpoint number. If there is no best checkpoint,
        it will return the last checkpoint. If there is no last checkpoint, it will return -1.

        Returns:
            int: best checkpoint number in integer
        '''
        checkpoint_num = -1
        best_checkpoint_name = self._get_deepracer_checkpoint(BEST_CHECKPOINT)
        if best_checkpoint_name and len(best_checkpoint_name.split("_Step")) > 0:
            checkpoint_num = int(best_checkpoint_name.split("_Step")[0])
        else:
            LOG.info("Unable to find the best deepracer checkpoint number. Getting the last checkpoint number")
            checkpoint_num = self.get_deepracer_last_checkpoint_number()
        return checkpoint_num

    def get_deepracer_last_checkpoint_number(self):
        '''get the last checkpoint number. If there is not last checkpoint, it will return -1

        Returns:
            int: last checkpoint number in integer
        '''
        checkpoint_num = -1
        last_checkpoint_name = self._get_deepracer_checkpoint(LAST_CHECKPOINT)
        # Verify if the last checkpoint name is present and is in right format
        if last_checkpoint_name and len(last_checkpoint_name.split("_Step")) > 0:
            checkpoint_num = int(last_checkpoint_name.split("_Step")[0])
        else:
            LOG.info("Unable to find the last deepracer checkpoint number.")
        return checkpoint_num

    def update_last_checkpoint(self, checkpoint_name, s3_kms_extra_args):
        '''Update only the last_checkpoint field in deepracer_checkpoints.json
        while preserving the best_checkpoint and existing lineage. 
        This is called when trainer saves a new checkpoint.
        NOTE: Does NOT update lineage - that's done by robomaker's persist()
        
        Args:
            checkpoint_name (str): New checkpoint name (e.g., "3_Step-405.ckpt")
            s3_kms_extra_args (dict): S3 KMS extra args
        '''
        import time
        try:
            # Download existing JSON to preserve best_checkpoint and lineage
            self._download()
            with open(self._local_path) as f:
                existing_data = json.load(f)
            os.remove(self._local_path)
        except Exception:
            # If no existing JSON, create empty structure
            existing_data = {}
        
        # Update last_checkpoint with new checkpoint info
        time_stamp = time.time()
        existing_data[LAST_CHECKPOINT] = {
            "name": checkpoint_name,
            "avg_eval_metric": existing_data.get(LAST_CHECKPOINT, {}).get("avg_eval_metric"),
            "time_stamp": time_stamp
        }
        
        # If no best_checkpoint yet, set it to this checkpoint
        if BEST_CHECKPOINT not in existing_data:
            existing_data[BEST_CHECKPOINT] = {
                "name": checkpoint_name,
                "avg_eval_metric": None,
                "time_stamp": time_stamp
            }
        
        # Initialize lineage array if not present
        if "_" not in existing_data:
            existing_data["_"] = []
        
        # Add lineage for current checkpoint
        if "_Step-" in checkpoint_name:
            checkpoint_num = int(checkpoint_name.split("_Step")[0])
            existing_lineage = existing_data.get("_", [])
            
            # If empty, check for pretrained (clone case)
            if len(existing_lineage) == 0:
                pretrained_prefix = os.environ.get("PRETRAINED_S3_PREFIX", "") or os.environ.get("SM_HP_PRETRAINED_S3_PREFIX", "")
                LOG.info("[Lineage] Algo check pretrained_prefix: '{}'".format(pretrained_prefix))
                
                if pretrained_prefix:
                    # Clone - inherit pretrained lineage immediately
                    pretrained_lineage = self._get_pretrained_lineage()
                    if pretrained_lineage:
                        existing_data["_"] = pretrained_lineage
                        existing_lineage = pretrained_lineage
                        LOG.info("[Lineage] Algo inherited {} entries from pretrained".format(len(pretrained_lineage)))
            
            # Check if this iteration already has lineage entry
            has_lineage = any(item.get("i") == checkpoint_num for item in existing_lineage)
            if not has_lineage:
                # Add lineage for this iteration
                existing_data = self._compute_and_add_lineage(existing_data, checkpoint_num, checkpoint_name)
        
        # Upload directly to S3 WITHOUT lineage update (lineage is updated by robomaker)
        body = json.dumps(existing_data)
        self._s3_client.put_object(bucket=self._bucket,
                                   s3_key=self._s3_key,
                                   body=bytes(body, encoding='utf-8'),
                                   s3_kms_extra_args=s3_kms_extra_args)
        LOG.info("[Checkpoint] Updated last_checkpoint to: {} (lineage preserved)".format(checkpoint_name))

    def _compute_and_add_lineage(self, body_data, checkpoint_num, checkpoint_name):
        '''Compute and add lineage entry for a specific checkpoint
        
        Args:
            body_data (dict): existing checkpoint data
            checkpoint_num (int): iteration number (e.g., 0)
            checkpoint_name (str): checkpoint name (e.g., "0_Step-0.ckpt")
            
        Returns:
            dict: updated body_data with lineage entry
        '''
        try:
            from markov.lineage_core import compute_pb_hash, compute_ckpt_hash, compute_final_hash
        except ImportError:
            LOG.info("[Lineage] lineage_core not available in algo, skipping")
            return body_data
        
        # Get s3 prefix (model/)
        s3_prefix = os.path.dirname(self._s3_key)
        
        # Get pb file content
        pb_key = os.path.join(s3_prefix, "model_{}.pb".format(checkpoint_num))
        pb_content = self._get_s3_content(pb_key)
        if not pb_content:
            LOG.info("[Lineage] Could not get pb content for iteration {} in algo".format(checkpoint_num))
            return body_data
        
        # Get ckpt file contents
        ckpt_prefix = "{}_Step-".format(checkpoint_num)
        ckpt_content = self._get_ckpt_content(s3_prefix, ckpt_prefix)
        if not ckpt_content:
            LOG.info("[Lineage] Could not get ckpt content for iteration {} in algo".format(checkpoint_num))
            return body_data
        
        # For first training, no previous finals
        prev_finals = []
        
        # Compute hashes
        pb_hash = compute_pb_hash(pb_content, prev_finals)
        ckpt_hash = compute_ckpt_hash(ckpt_content, prev_finals)
        final_hash = compute_final_hash(pb_hash, ckpt_hash)
        
        import time
        new_entry = {
            "i": checkpoint_num,
            "pb": pb_hash,
            "ckpt": ckpt_hash,
            "final": final_hash,
            "t": int(time.time())
        }
        
        body_data["_"].append(new_entry)
        LOG.info("[Lineage] Algo added i={}: pb={}, final={}".format(checkpoint_num, pb_hash[:16], final_hash[:16]))
        return body_data

    def _download(self):
        '''download deepracer checkpoint json file from s3 bucket
        '''
        local_dir = os.path.dirname(self._local_path)
        if not os.path.exists(local_dir):
            os.makedirs(local_dir)

        self._s3_client.download_file(bucket=self._bucket,
                                      s3_key=self._s3_key,
                                      local_path=self._local_path)
        LOG.info("[s3] Successfully downloaded deepracer checkpoint json from \
                 s3 key {} to local {}.".format(self._s3_key,
                                                self._local_path))

    def persist(self, body, s3_kms_extra_args):
        '''upload metrics into s3 bucket

        Args:
            body (str): s3 upload string
            s3_kms_extra_args (dict): s3 key management service extra argument

        '''
        # Robomaker calls this with evaluation results (best_checkpoint update)
        # But algo updates last_checkpoint separately, so we need to merge
        try:
            incoming_data = json.loads(body)
            
            # Get current S3 data to preserve last_checkpoint and lineage
            try:
                self._download()
                with open(self._local_path) as f:
                    current_data = json.load(f)
                os.remove(self._local_path)
            except Exception:
                current_data = {}
            
            # Preserve last_checkpoint from S3 (algo updates this)
            if LAST_CHECKPOINT in current_data:
                incoming_data[LAST_CHECKPOINT] = current_data[LAST_CHECKPOINT]
            
            # Preserve lineage from S3 (algo updates this)
            if "_" in current_data:
                incoming_data["_"] = current_data["_"]
            
            # Update lineage if needed (for iterations not yet in lineage)
            incoming_data = self._update_lineage(incoming_data)
            body = json.dumps(incoming_data)
        except Exception as ex:
            LOG.info("[Lineage] Failed to merge/update: {}".format(ex))
        
        self._s3_client.put_object(bucket=self._bucket,
                                   s3_key=self._s3_key,
                                   body=bytes(body, encoding='utf-8'),
                                   s3_kms_extra_args=s3_kms_extra_args)
        LOG.info("[s3] Successfully uploaded deepracer checkpoint to \
                 s3 bucket {} with s3 key {}.".format(self._bucket, self._s3_key))

    def _update_lineage(self, body_data):
        '''Update lineage hash chain in checkpoint json with salted hashes
        
        Args:
            body_data (dict): checkpoint data dict with best/last checkpoint info
            
        Returns:
            dict: updated body_data with lineage
        '''
        LOG.info("[Lineage] _update_lineage called")
        try:
            from markov.lineage_core import compute_pb_hash, compute_ckpt_hash, compute_final_hash
        except ImportError:
            LOG.info("[Lineage] lineage_core not available, skipping")
            return body_data
        
        # Get current checkpoint number from last_checkpoint
        last_info = body_data.get(LAST_CHECKPOINT, {})
        last_name = last_info.get("name", "")
        if not last_name:
            return body_data
        
        checkpoint_num = int(last_name.split("_Step")[0]) if "_Step" in last_name else -1
        if checkpoint_num < 0:
            return body_data
        
        # Extract step count from checkpoint name (e.g., "3_Step-0.ckpt" -> step=0)
        # For clones (pretrained exists): step=0 means model just copied, only inherit lineage
        # For first training (no pretrained): step=0 should also be added to lineage as i=0
        try:
            step_part = last_name.split("_Step-")[1].split(".ckpt")[0]
            step_count = int(step_part)
            if step_count == 0:
                existing_lineage = self._get_pretrained_lineage()
                if existing_lineage:
                    # Clone: only inherit pretrained lineage (no new entry; preserve the cloned model's i)
                    body_data["_"] = existing_lineage
                    LOG.info("[Lineage] Clone detected (step=0): inherited {} entries from pretrained".format(len(existing_lineage)))
                    return body_data
                # First training: also add i=0 to the lineage (fall through to the logic below)
                LOG.info("[Lineage] First training (step=0): will add iteration 0 to lineage")
        except (IndexError, ValueError):
            pass  # Continue with normal lineage update
        
        # Get s3 prefix (model/)
        s3_prefix = os.path.dirname(self._s3_key)
        
        # Get pb file content
        pb_key = os.path.join(s3_prefix, "model_{}.pb".format(checkpoint_num))
        pb_content = self._get_s3_content(pb_key)
        if not pb_content:
            LOG.info("[Lineage] Could not get pb content for iteration {}".format(checkpoint_num))
            return body_data
        
        # Get ckpt file contents (concatenated)
        ckpt_prefix = "{}_Step-".format(checkpoint_num)
        ckpt_content = self._get_ckpt_content(s3_prefix, ckpt_prefix)
        if not ckpt_content:
            LOG.info("[Lineage] Could not get ckpt content for iteration {}".format(checkpoint_num))
            return body_data
        
        # Get existing lineage (first try current model, then pretrained)
        existing_lineage = []
        try:
            self._download()
            with open(self._local_path) as f:
                existing_data = json.load(f)
                existing_lineage = existing_data.get("_", [])
            os.remove(self._local_path)
            LOG.info("[Lineage] Loaded {} existing entries from current model".format(len(existing_lineage)))
        except Exception as ex:
            LOG.info("[Lineage] No existing lineage in current model: {}".format(ex))
        
        # If no existing lineage, try to inherit from pretrained model
        if not existing_lineage:
            LOG.info("[Lineage] Trying to inherit from pretrained model...")
            existing_lineage = self._get_pretrained_lineage()
            LOG.info("[Lineage] After pretrained check, have {} entries".format(len(existing_lineage)))
        
        # Get previous final hashes for chain
        prev_finals = [item.get("final", "") for item in existing_lineage]
        
        # Compute hashes using lineage_core (with hidden salt)
        pb_hash = compute_pb_hash(pb_content, prev_finals)
        ckpt_hash = compute_ckpt_hash(ckpt_content, prev_finals)
        final_hash = compute_final_hash(pb_hash, ckpt_hash)
        
        # Add new entry
        import time
        new_entry = {
            "i": checkpoint_num,
            "pb": pb_hash,
            "ckpt": ckpt_hash,
            "final": final_hash,
            "t": int(time.time())
        }
        
        # Avoid duplicates
        if not any(item.get("i") == checkpoint_num for item in existing_lineage):
            existing_lineage.append(new_entry)
        
        # Store lineage
        body_data["_"] = existing_lineage
        
        LOG.info("[Lineage] Added hashes for iteration {}: pb={}, ckpt={}, final={}".format(
            checkpoint_num, pb_hash, ckpt_hash, final_hash))
        return body_data
    
    def _get_s3_content(self, s3_key):
        '''Get raw content of S3 object
        
        Args:
            s3_key (str): S3 object key
            
        Returns:
            bytes: File content or None
        '''
        try:
            import tempfile
            with tempfile.NamedTemporaryFile(delete=False) as tmp:
                tmp_path = tmp.name
            
            self._s3_client.download_file(bucket=self._bucket,
                                          s3_key=s3_key,
                                          local_path=tmp_path)
            
            with open(tmp_path, 'rb') as f:
                content = f.read()
            
            os.remove(tmp_path)
            return content
        except Exception as ex:
            LOG.info("[Lineage] Failed to get content for {}: {}".format(s3_key, ex))
            return None
    
    def _get_ckpt_content(self, s3_prefix, ckpt_prefix):
        '''Get concatenated content of checkpoint files
        
        Args:
            s3_prefix (str): S3 prefix (model/)
            ckpt_prefix (str): Checkpoint prefix (e.g., "14_Step-")
            
        Returns:
            bytes: Concatenated checkpoint file content or None
        '''
        try:
            import tempfile
            contents = []
            
            # List objects with prefix
            response = self._s3_client.list_objects_v2(bucket=self._bucket,
                                                       prefix=s3_prefix)
            
            if "Contents" not in response:
                return None
            
            for obj in response["Contents"]:
                key = obj["Key"]
                filename = os.path.basename(key)
                
                # Match ckpt files: {N}_Step-*.ckpt.*
                if filename.startswith(ckpt_prefix) and ".ckpt" in filename:
                    with tempfile.NamedTemporaryFile(delete=False) as tmp:
                        tmp_path = tmp.name
                    
                    self._s3_client.download_file(bucket=self._bucket,
                                                  s3_key=key,
                                                  local_path=tmp_path)
                    
                    with open(tmp_path, 'rb') as f:
                        contents.append(f.read())
                    
                    os.remove(tmp_path)
            
            return b''.join(sorted(contents)) if contents else None
        except Exception as ex:
            LOG.info("[Lineage] Failed to get ckpt content: {}".format(ex))
            return None

    def _get_pretrained_lineage(self):
        '''Get lineage from pretrained model if available
        
        Returns:
            list: Lineage array from pretrained model, or empty list
        '''
        try:
            import tempfile
            
            # Check for pretrained model - from env vars (robomaker: PRETRAINED_S3_PREFIX, sagemaker: SM_HP_PRETRAINED_S3_PREFIX)
            pretrained_prefix = os.environ.get("PRETRAINED_S3_PREFIX", "") or os.environ.get("SM_HP_PRETRAINED_S3_PREFIX", "")
            
            if not pretrained_prefix:
                # Fallback: try hyperparameters.json (for sagemaker container)
                hyperparams_path = "/opt/ml/input/config/hyperparameters.json"
                if os.path.exists(hyperparams_path):
                    with open(hyperparams_path) as f:
                        hyperparams = json.load(f)
                        pretrained_prefix = hyperparams.get("pretrained_s3_prefix", "")
            
            if not pretrained_prefix:
                LOG.info("[Lineage] No pretrained model configured")
                return []
            
            LOG.info("[Lineage] Found pretrained model: {}".format(pretrained_prefix))
            
            # Build s3 key for pretrained model's checkpoint json
            pretrained_key = os.path.normpath(os.path.join(
                pretrained_prefix,
                DEEPRACER_CHECKPOINT_KEY_POSTFIX))
            
            # Download to temp file
            with tempfile.NamedTemporaryFile(delete=False, suffix='.json') as tmp:
                tmp_path = tmp.name
            
            self._s3_client.download_file(bucket=self._bucket,
                                          s3_key=pretrained_key,
                                          local_path=tmp_path)
            
            with open(tmp_path) as f:
                pretrained_data = json.load(f)
            
            os.remove(tmp_path)
            
            lineage = pretrained_data.get("_", [])
            
            # Filter lineage based on which checkpoint was selected (best/last)
            pretrained_checkpoint = os.environ.get("PRETRAINED_CHECKPOINT", "") or os.environ.get("SM_HP_PRETRAINED_CHECKPOINT", "")
            if not pretrained_checkpoint:
                hyperparams_path = "/opt/ml/input/config/hyperparameters.json"
                if os.path.exists(hyperparams_path):
                    with open(hyperparams_path) as f:
                        hyperparams = json.load(f)
                        pretrained_checkpoint = hyperparams.get("pretrained_checkpoint", "last")
            
            # Get the iteration number of the selected checkpoint
            max_iteration = -1
            if pretrained_checkpoint == "best":
                best_name = pretrained_data.get(BEST_CHECKPOINT, {}).get("name", "")
                if best_name and "_Step" in best_name:
                    max_iteration = int(best_name.split("_Step")[0])
                    LOG.info("[Lineage] Cloning from best checkpoint, limiting lineage to i<={}".format(max_iteration))
            elif pretrained_checkpoint == "last":
                last_name = pretrained_data.get(LAST_CHECKPOINT, {}).get("name", "")
                if last_name and "_Step" in last_name:
                    max_iteration = int(last_name.split("_Step")[0])
                    LOG.info("[Lineage] Cloning from last checkpoint, limiting lineage to i<={}".format(max_iteration))
            else:
                # Specific checkpoint number
                try:
                    max_iteration = int(pretrained_checkpoint)
                    LOG.info("[Lineage] Cloning from checkpoint {}, limiting lineage to i<={}".format(pretrained_checkpoint, max_iteration))
                except ValueError:
                    pass
            
            # Filter lineage to only include entries up to max_iteration
            if max_iteration >= 0 and lineage:
                lineage = [entry for entry in lineage if entry.get("i", 0) <= max_iteration]
                LOG.info("[Lineage] Filtered lineage to {} entries (i<={})", len(lineage), max_iteration)
            
            if lineage:
                LOG.info("[Lineage] Inherited {} entries from pretrained model".format(len(lineage)))
            return lineage
            
        except Exception as ex:
            LOG.info("[Lineage] Could not get pretrained lineage: {}".format(ex))
            return []
